import React from "react";
import MessageCard from "./MessageCard";
import { MessageListProps, MessageItem } from "../types";

/**
 * Componente MessageList da aplicação
 * Exibe uma lista de itens/mensagens com suporte a seleção múltipla
 * 
 * @param items - Array de itens/mensagens para exibir
 * @param selectedIds - Array com IDs dos itens selecionados
 * @param setSelectedIds - Função para atualizar a seleção de itens
 */
const MessageList = ({ items, selectedIds, setSelectedIds }: MessageListProps) => {
  return (
    <div className="p-4">
      {/* Lista de itens/mensagens */}
      <div className="space-y-2">
        {items.map((item: MessageItem) => (
          <MessageCard
            key={item.id}
            item={item}
            selectedIds={selectedIds}
            setSelectedIds={setSelectedIds}
          />
        ))}
      </div>
      
      {/* Mensagem quando não há itens */}
      {items.length === 0 && (
        <div className="text-center py-8">
          <div className="text-gray-400 mb-2">
            <svg className="mx-auto h-12 w-12 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 13V6a2 2 0 00-2-2H6a2 2 0 00-2 2v7m16 0v5a2 2 0 01-2 2H6a2 2 0 01-2-2v-5m16 0h-2.586a1 1 0 00-.707.293l-2.414 2.414a1 1 0 01-.707.293h-3.172a1 1 0 01-.707-.293l-2.414-2.414A1 1 0 006.586 13H4" />
            </svg>
          </div>
          <h3 className="text-lg font-medium text-gray-900 mb-1">
            Nenhum item encontrado
          </h3>
          <p className="text-sm text-gray-500">
            Selecione um menu na barra lateral para ver os itens disponíveis.
          </p>
        </div>
      )}
    </div>
  );
};

export default MessageList;
